class KVStore:
    def __init__(self):
        self._data = {}

    def get(self, key, default=None):
        return self._data.get(key, default)

    def set(self, key, value):
        self._data[key] = value

    def delete(self, key):
        self._data.pop(key, None)

    def exists(self, key):
        return key in self._data

    def keys(self):
        return list(self._data.keys())
